class Solution {
    private static final int MOD = 1_000_000_007;
    private static final int MAX_BITS = 800;
    private static final int MAX_K = 5;
    private static int[][] C;
    private static int[] steps;

    static {
        C = new int[MAX_BITS + 1][MAX_BITS + 1];
        for (int n = 0; n <= MAX_BITS; n++) {
            C[n][0] = 1;
            for (int k = 1; k <= n; k++) {
                C[n][k] = (C[n - 1][k - 1] + C[n - 1][k]) % MOD;
            }
        }
        steps = new int[MAX_BITS + 1];
        for (int i = 2; i <= MAX_BITS; i++) {
            int cnt = Integer.bitCount(i);
            steps[i] = steps[cnt] + 1;
        }
    }

    public int countKReducibleNumbers(String s, int k) {
        int len = s.length();
        int total = 0;
        for (int ones = 1; ones <= len; ones++) {
            if (steps[ones] < k) {
                total = (total + countNumbersWithOnes(s, ones)) % MOD;
            }
        }
        return total;
    }

    private int countNumbersWithOnes(String s, int ones) {
        int len = s.length();
        int[][] dp = new int[len + 1][len + 1];
        dp[0][0] = 1;
        for (int i = 1; i <= len; i++) {
            char c = s.charAt(i - 1);
            for (int j = 0; j <= len; j++) {
                if (c == '0') {
                    dp[i][j] = dp[i - 1][j];
                } else {
                    dp[i][j] = (dp[i - 1][j] + (j > 0 ? dp[i - 1][j - 1] : 0)) % MOD;
                    if (j > 0) {
                        dp[i][j] = (dp[i][j] + C[len - i][j]) % MOD;
                    }
                }
            }
        }
        return dp[len][ones];
    }
}
